// 0) 取 Supabase 多筆資料（從上一節點 Get many rows 來）
const rows = $input.all().map(i => i.json);

// 1) 取 Webhook 的資料
const webhook = $items("Webhook")[0].json;

// 2) 使用者輸入
const keyword = webhook.body?.keyword || webhook.body?.subject || "";
const category = webhook.body?.category || "";
const title = webhook.body?.title || "";

// 3) 只取 description/detail 當語料庫：去空白、截斷、去重、最多 30 筆
const details = rows
  .map(r => (r.description || r.detail || "").replace(/\s+/g, " ").trim())
  .filter(t => t.length > 0)
  .map(t => t.slice(0, 200));

const uniq = [...new Set(details)];
const finalDetails = uniq.slice(0, 30);

// 4) 回傳單一 item 給 MiniMax
return [
  {
    json: {
      keyword,
      category,
      title,
      details: finalDetails,
      count: finalDetails.length
    }
  }
];

// 解析 MiniMax API 回應
const response = $input.first().json;

let result = {
  ok: true,
  features: [],
  specs: {},
  scenarios: "",
  notes: ""
};

try {
  // MiniMax 回傳格式
  const content = response.choices[0].message.content;

  // 嘗試解析為 JSON
  const parsed = JSON.parse(content);
  result.features = parsed.features || [];
  result.specs = parsed.specs || {};
  result.scenarios = parsed.scenarios || "";
  result.notes = parsed.notes || "";
} catch (e) {
  result.ok = false;
  result.error = "解析失敗: " + e.message;
  // 保留原始回應供除錯
  result.raw = response.choices?.[0]?.message?.content || "";
}

return [{ json: result }];
